-- My Daily Routine savollar
WITH art AS (SELECT id FROM articles WHERE title = 'My Daily Routine' LIMIT 1)
INSERT INTO article_questions (article_id, question, option_a, option_b, option_c, option_d, correct_answer, order_num)
SELECT art.id, q.question, q.a, q.b, q.c, q.d, q.correct, q.num FROM art,
(VALUES
  (1, 'What time does the person wake up?', '6 o''clock', '7 o''clock', '8 o''clock', '9 o''clock', 'B'),
  (2, 'What does the person eat for breakfast?', 'Rice and milk', 'Bread, eggs, and tea', 'Cereal and juice', 'Pancakes and coffee', 'B'),
  (3, 'When does school start?', '7 o''clock', '9 o''clock', '8 o''clock', '10 o''clock', 'C'),
  (4, 'What does the person do in the evening?', 'Goes to the gym', 'Watches TV or reads books', 'Meets friends', 'Cooks dinner', 'B'),
  (5, 'What time does the person go to bed?', '9 o''clock', '11 o''clock', '10 o''clock', '12 o''clock', 'C')
) AS q(num, question, a, b, c, d, correct);

