  (1, 'Where did pizza originally come from?', 'France', 'Italy', 'Greece', 'Spain', 'B'),
  (2, 'When did Italian immigrants bring pizza to America?', 'Early 1700s', 'Late 1800s', 'Early 1900s', 'Mid 1900s', 'B'),
  (3, 'When did the first New York pizzeria open?', '1890', '1895', '1905', '1910', 'C'),
  (4, 'What helped make pizza popular in America after WWII?', 'Italian chefs moved to America', 'American soldiers tried pizza in Italy', 'Pizza was cheap to make', 'TV commercials promoted pizza', 'B'),
  (5, 'What are the ingredients of a Margherita pizza?', 'Mushrooms, olives, peppers', 'Meat, onion, garlic', 'Tomato, mozzarella, basil', 'Cheese, bacon, herbs', 'C')
) AS q(num, question, a, b, c, d, correct);

